function ScoreBar({score,max=5,color,invert}){const d=invert?6-score:score;return <div style={{display:"flex",gap:3}}>{Array.from({length:max},(_,i)=><div key={i} style={{width:22,height:7,borderRadius:3,background:i<d?color:C.border}}/>)}</div>;}

function Expand({icon,title,children,open:d=false}){const[o,setO]=useState(d);return <div style={{borderBottom:"1px solid "+C.border}}><button onClick={()=>setO(!o)} style={{width:"100%",padding:"14px 0",background:"none",border:"none",display:"flex",alignItems:"center",justifyContent:"space-between",cursor:"pointer",fontFamily:sans}}><span style={{display:"flex",alignItems:"center",gap:10}}><span style={{fontSize:16}}>{icon}</span><span style={{fontSize:14,fontWeight:600,color:C.text}}>{title}</span></span><span style={{color:C.textMuted,transform:o?"rotate(180deg)":"none",transition:"0.2s"}}>▾</span></button>{o&&<div style={{paddingBottom:16}}>{children}</div>}</div>;}




function Sparrow() {
  const [pos, setPos] = useState({x: -80, y: 90});
  const [wing, setWing] = useState(false);
  const [flip, setFlip] = useState(false);
  const [landed, setLanded] = useState(false);
  const [btnPos, setBtnPos] = useState(null);

  useEffect(() => {
    // Find the teal CTA button position after mount
    const findBtn = () => {
      const btns = document.querySelectorAll("button");
      for (const b of btns) {
        if (b.textContent.includes("Explore the HR Toolkit") && b.style.background) {
          const r = b.getBoundingClientRect();
          setBtnPos({x: r.left + r.width / 2 - 40, y: r.top - 42});
          break;
        }
      }
    };
    setTimeout(findBtn, 500);

    let f = 0;
    let prevX = 700;
    const id = setInterval(() => {
      if (landed) return;
      f++;
      const t = f * 0.0175;
      const px = Math.sin(t) * 550 + 650;
      const py = Math.sin(t * 2) * 280 + 380;
      setFlip(px < prevX);
      prevX = px;
      setPos({x: px, y: py});
      if (f % 5 === 0) setWing(w => !w);
    }, 25);

    // Land after 30 seconds
    const landTimer = setTimeout(() => {
      setLanded(true);
      setWing(false);
      setFlip(false);
    }, 15000);

    return () => { clearInterval(id); clearTimeout(landTimer); };
  }, [landed]);

  const landX = btnPos ? btnPos.x : 200;
  const landY = btnPos ? btnPos.y : 300;
  const finalPos = landed ? {x: landX, y: landY} : pos;

  return (
    <div style={{position:"fixed",top:0,left:0,width:"100%",height:"100%",pointerEvents:"none",zIndex:0,overflow:"hidden"}}>
      <svg width="80" height="50" viewBox="0 0 44 28" style={{
        position:"absolute",
        left: finalPos.x,
        top: finalPos.y,
        opacity: landed ? 0.35 : 0.22,
        transform: flip ? "scaleX(-1)" : "scaleX(1)",
        transition: landed ? "left 1.5s ease, top 1.5s ease, opacity 1s ease" : "transform 0.3s ease",
      }}>
        <ellipse cx="22" cy="14" rx="7" ry="3.5" fill="#13798A"/>
        <circle cx="30" cy="12" r="3" fill="#13798A"/>
        <circle cx="31.5" cy="11.5" r="0.7" fill="#0B2545"/>
        <polygon points="33,12 36,11 33,11" fill="#D4A853"/>
        <path d="M15 14 L4 10 L8 14 L4 18 Z" fill="#13798A" opacity="0.8"/>
        {landed
          ? <path d="M22 12 Q18 8 12 10 Q16 10 22 12" fill="#13798A" opacity="0.6"/>
          : wing
            ? <path d="M22 12 Q16 3 6 7 Q14 7 22 12" fill="#13798A" opacity="0.6"/>
            : <path d="M22 16 Q16 23 6 21 Q14 19 22 16" fill="#13798A" opacity="0.6"/>
        }
      </svg>
    </div>
  );
}


